import React, { useCallback, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import { ArrowLeft, Sparkles } from "lucide-react";

import Input from "@/components/primitives/Input";
import Textarea from "@/components/primitives/Textarea";
import TransactionStatus from "@/components/feedback/TransactionStatus";
import { useOpenWalletConnect } from "@/components/wallet/WalletConnectModal";
import {
  validateBio,
  validateDisplayName,
  validateUsername,
} from "@/utils/validation";
import { useContract, useUsernameCheck } from "@/hooks";
import { useToastStore } from "@/state/toastStore";
import { useWalletStore } from "@/state/walletStore";
import { ProfileFormData } from "@/types/profile";
import {
  ERRORS,
  formatUserFacingContractError,
  isAlreadyRegisteredContractError,
  isLikelyNetworkError,
} from "@/utils/error";
import { TERMINAL_DEFAULT_PATH } from "@/constants/terminalNav";
import { getSiteOrigin } from "@/config/site";
import RegisterSuccessCelebration from "@/sections/profile/RegisterSuccessCelebration";
import {
  CREATOR_INTERESTS,
  MAX_INTEREST_PICKS,
} from "@/sections/profile/registerWizardConstants";
import AvatarImageField from "@/sections/profile/AvatarImageField";
import { validateProfileImageUrlField } from "@/utils/profileImageUrl";

const REGISTER_WALLET_REQUIRED_MESSAGE =
  "Connect Wallet · then retry.";

type TxStatus = "idle" | "signing" | "submitting" | "confirming" | "success" | "error";

const STEP_LABELS = ["Start", "Your link", "About you", "Interests", "Extras"] as const;

interface FormErrors {
  username?: string;
  displayName?: string;
  bio?: string;
  imageUrl?: string;
  xHandle?: string;
}

function validateFinal(
  data: ProfileFormData,
  available: boolean | null,
  checking: boolean,
): FormErrors {
  const errors: FormErrors = {};
  const usernameValidation = validateUsername(data.username);
  if (!usernameValidation.valid) {
    errors.username = usernameValidation.error;
  } else if (!checking && available === false) {
    errors.username = "That handle is already taken — try another.";
  } else if (checking) {
    errors.username = "Checking availability…";
  }
  const displayNameValidation = validateDisplayName(data.displayName);
  if (!displayNameValidation.valid) {
    errors.displayName = displayNameValidation.error;
  }
  const bioValidation = validateBio(data.bio);
  if (!bioValidation.valid) {
    errors.bio = bioValidation.error;
  }
  if (data.imageUrl.trim()) {
    const imgErr = validateProfileImageUrlField(data.imageUrl);
    if (imgErr) errors.imageUrl = imgErr;
  }
  return errors;
}

const RegisterWizard: React.FC = () => {
  const navigate = useNavigate();
  const connected = useWalletStore((s) => s.connected);
  const openWalletConnect = useOpenWalletConnect();

  const [step, setStep] = useState(0);
  const [form, setForm] = useState<ProfileFormData>({
    username: "",
    displayName: "",
    bio: "",
    imageUrl: "",
    xHandle: "",
  });
  const [interests, setInterests] = useState<Set<string>>(new Set());
  const [errors, setErrors] = useState<FormErrors>({});
  const [txStatus, setTxStatus] = useState<TxStatus>("idle");
  const [txHash, setTxHash] = useState<string | undefined>(undefined);
  const [txError, setTxError] = useState<string | undefined>(undefined);
  const [celebrationUsername, setCelebrationUsername] = useState<string | null>(null);

  const { registerProfile } = useContract();
  const { addToast } = useToastStore();
  const { available, checking, error: availabilityError } = useUsernameCheck(form.username);

  const siteOrigin = getSiteOrigin();

  const mergedBio = useMemo(() => {
    const tagLine =
      interests.size > 0
        ? `Tags: ${Array.from(interests).join(", ")}\n\n`
        : "";
    return `${tagLine}${form.bio.trim()}`.trim();
  }, [interests, form.bio]);

  const handleChange =
    (field: keyof ProfileFormData) =>
    (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
      setForm((prev) => ({ ...prev, [field]: e.target.value }));
      setErrors((prev) => ({ ...prev, [field]: undefined }));
    };

  const toggleInterest = useCallback((tag: string) => {
    setInterests((prev) => {
      const next = new Set(prev);
      if (next.has(tag)) {
        next.delete(tag);
      } else if (next.size < MAX_INTEREST_PICKS) {
        next.add(tag);
      }
      return next;
    });
  }, []);

  const validateStep = useCallback((): boolean => {
    const e: FormErrors = {};
    if (step === 1) {
      const u = validateUsername(form.username);
      if (!u.valid) e.username = u.error;
      else if (checking) e.username = "Checking availability…";
      else if (available === false) e.username = "That handle is already taken.";
    }
    if (step === 2) {
      const d = validateDisplayName(form.displayName);
      if (!d.valid) e.displayName = d.error;
      const b = validateBio(form.bio.trim());
      if (!b.valid) e.bio = b.error;
    }
    if (step === 3) {
      if (mergedBio.length > 280) {
        e.bio = "Shorten your bio or pick fewer tags (max 280 characters total).";
      }
    }
    setErrors(e);
    return Object.keys(e).length === 0;
  }, [step, form.username, form.displayName, form.bio, mergedBio, checking, available]);

  const goNext = useCallback(() => {
    if (step === 0) {
      if (!connected) {
        openWalletConnect();
        return;
      }
      setStep(1);
      return;
    }
    if (!validateStep()) return;
    setStep((s) => Math.min(s + 1, 4));
  }, [step, connected, openWalletConnect, validateStep]);

  const goBack = useCallback(() => {
    setStep((s) => Math.max(s - 1, 0));
    setErrors({});
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const data: ProfileFormData = {
      username: form.username.trim().toLowerCase(),
      displayName: form.displayName.trim(),
      bio: mergedBio,
      imageUrl: form.imageUrl.trim(),
      xHandle: form.xHandle.trim().replace(/^@/, ""),
    };
    const validationErrors = validateFinal(data, available, checking);
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      return;
    }
    if (data.bio.length > 280) {
      setErrors({ bio: "Bio must be 280 characters or fewer." });
      return;
    }

    try {
      setCelebrationUsername(null);
      setTxStatus("signing");
      setTxError(undefined);
      setTxHash(undefined);
      setTxStatus("submitting");
      const hash = await registerProfile(data);
      setTxStatus("confirming");
      setTxHash(hash);
      setTxStatus("success");
      setCelebrationUsername(data.username);
      addToast({
        message: "You're live — share your link to start receiving tips.",
        type: "success",
        duration: 5000,
      });
    } catch (err) {
      if (isAlreadyRegisteredContractError(err)) {
        addToast({
          message: "You already have a creator page — opening your dashboard.",
          type: "success",
          duration: 4000,
        });
        navigate(TERMINAL_DEFAULT_PATH, { replace: true });
        setTxStatus("idle");
        setTxError(undefined);
        return;
      }
      setTxStatus("error");
      if (isLikelyNetworkError(err)) {
        setTxError(ERRORS.NETWORK);
        return;
      }
      const msg = formatUserFacingContractError(err);
      const lower = msg.toLowerCase();
      if (lower.includes("wallet not connected")) {
        setTxError(REGISTER_WALLET_REQUIRED_MESSAGE);
      } else if (
        lower.includes("reject") ||
        lower.includes("denied") ||
        lower.includes("cancel") ||
        lower.includes("user declined")
      ) {
        setTxError("You declined the signature — try again when ready.");
      } else {
        setTxError(msg);
      }
    }
  };

  const handleRegisterTxRetry = () => {
    if (txError === REGISTER_WALLET_REQUIRED_MESSAGE) {
      openWalletConnect();
    }
    setTxStatus("idle");
    setTxError(undefined);
  };

  const registerTxRetryLabel =
    txError === REGISTER_WALLET_REQUIRED_MESSAGE ? "Connect wallet" : undefined;

  const isSubmitting = ["signing", "submitting", "confirming"].includes(txStatus);

  if (txStatus === "success" && celebrationUsername) {
    return (
      <RegisterSuccessCelebration
        username={celebrationUsername}
        pageUrl={`${siteOrigin}/@${celebrationUsername}`}
        txHash={txHash}
      />
    );
  }

  const progressPct = ((step + 1) / STEP_LABELS.length) * 100;

  return (
    <div className="space-y-8">
      <div className="space-y-2">
        <div className="flex items-center justify-between gap-2">
          <p className="font-body text-xs font-semibold uppercase tracking-[0.12em] text-zap-accent">
            Step {step + 1} of {STEP_LABELS.length}
          </p>
          <p className="font-body text-xs text-zap-ink-muted">{STEP_LABELS[step]}</p>
        </div>
        <div
          className="h-1.5 w-full overflow-hidden rounded-full bg-zap-border"
          role="progressbar"
          aria-valuenow={step + 1}
          aria-valuemin={1}
          aria-valuemax={STEP_LABELS.length}
        >
          <div
            className="h-full rounded-full bg-zap-brand transition-[width] duration-300 ease-out"
            style={{ width: `${progressPct}%` }}
          />
        </div>
      </div>

      <form onSubmit={step === 4 ? handleSubmit : (ev) => ev.preventDefault()} className="space-y-6">
        {step === 0 && (
          <div className="space-y-5 text-center sm:text-left">
            <div className="mx-auto flex h-14 w-14 items-center justify-center rounded-2xl bg-zap-brand-dim text-zap-brand sm:mx-0">
              <Sparkles className="h-7 w-7" strokeWidth={1.75} aria-hidden />
            </div>
            <div>
              <h2 className="font-body text-2xl font-semibold tracking-tight text-zap-ink md:text-3xl">
                Welcome to Zap402
              </h2>
              <p className="mt-3 font-body text-base leading-relaxed text-zap-ink-muted">
                A few quick steps and you’ll have a public tip page — USDC on Stellar, your wallet,
                your rules. It only takes a minute.
              </p>
            </div>
            {!connected ? (
              <p className="rounded-xl border border-dashed border-zap-border bg-zap-bg-alt px-4 py-3 font-body text-sm text-zap-ink-muted">
                Connect a Stellar wallet first — we’ll ask you to sign when your profile goes live.
              </p>
            ) : (
              <p className="rounded-xl border border-zap-border/60 bg-zap-success-dim/30 px-4 py-3 font-body text-sm text-zap-ink-muted dark:bg-zap-teal-dim/20">
                Wallet connected. Let’s pick your link next.
              </p>
            )}
          </div>
        )}

        {step === 1 && (
          <div className="space-y-4">
            <div>
              <h2 className="font-body text-xl font-semibold text-zap-ink md:text-2xl">
                Pick your username
              </h2>
              <p className="mt-1 font-body text-sm text-zap-ink-muted">
                This becomes your public link — you can update your display name later.
              </p>
            </div>
            <Input
              variant="editorial"
              label="Username"
              placeholder="your_handle"
              value={form.username}
              onChange={handleChange("username")}
              error={errors.username}
              disabled={isSubmitting}
              maxLength={32}
              required
              className="pr-11"
              endAdornment={
                form.username && !errors.username ? (
                  <>
                    {checking && (
                      <div
                        className="h-4 w-4 animate-spin rounded-full border-2 border-zap-border border-t-zap-brand"
                        aria-hidden
                      />
                    )}
                    {!checking && available === true && (
                      <span className="text-green-600 dark:text-green-400" aria-hidden>
                        ✓
                      </span>
                    )}
                    {!checking && available === false && (
                      <span className="text-red-600 dark:text-red-400" aria-hidden>
                        ×
                      </span>
                    )}
                  </>
                ) : null
              }
            />
            <p className="break-all font-body text-sm text-zap-ink-muted">
              <span className="font-medium text-zap-ink">Your page · </span>
              <span className="font-mono text-zap-ink">
                {siteOrigin}/@{form.username || "username"}
              </span>
            </p>
            {form.username && !errors.username && availabilityError && (
              <p className="text-sm text-amber-800 dark:text-amber-300">{availabilityError}</p>
            )}
          </div>
        )}

        {step === 2 && (
          <div className="space-y-4">
            <div>
              <h2 className="font-body text-xl font-semibold text-zap-ink md:text-2xl">
                About you
              </h2>
              <p className="mt-1 font-body text-sm text-zap-ink-muted">
                How should fans know you? Keep it short — you can edit anytime.
              </p>
            </div>
            <Input
              variant="editorial"
              label="Display name"
              placeholder="Your name or channel"
              value={form.displayName}
              onChange={handleChange("displayName")}
              error={errors.displayName}
              disabled={isSubmitting}
              maxLength={64}
              required
            />
            <Textarea
              variant="editorial"
              label="Bio"
              placeholder="Introduce yourself so supporters know what you create…"
              value={form.bio}
              onChange={handleChange("bio")}
              error={errors.bio}
              disabled={isSubmitting}
              maxLength={280}
              rows={4}
            />
          </div>
        )}

        {step === 3 && (
          <div className="space-y-4">
            <div>
              <h2 className="font-body text-xl font-semibold text-zap-ink md:text-2xl">
                What do you create?
              </h2>
              <p className="mt-1 font-body text-sm text-zap-ink-muted">
                Pick up to {MAX_INTEREST_PICKS} tags — we’ll add them to your bio. Optional, but it
                helps fans find you.
              </p>
            </div>
            <div className="flex flex-wrap gap-2">
              {CREATOR_INTERESTS.map((tag) => {
                const selected = interests.has(tag);
                const disabled = !selected && interests.size >= MAX_INTEREST_PICKS;
                return (
                  <button
                    key={tag}
                    type="button"
                    disabled={disabled || isSubmitting}
                    onClick={() => toggleInterest(tag)}
                    className={`rounded-full border px-3 py-1.5 font-body text-sm font-medium transition-colors ${
                      selected
                        ? "border-zap-brand bg-zap-brand text-zap-bg"
                        : "border-zap-border-bright bg-zap-bg-raised text-zap-ink hover:border-zap-brand/50 disabled:opacity-40"
                    }`}
                  >
                    {tag}
                  </button>
                );
              })}
            </div>
            {errors.bio && <p className="text-sm text-red-600 dark:text-red-400">{errors.bio}</p>}
          </div>
        )}

        {step === 4 && (
          <div className="space-y-4">
            <div>
              <h2 className="font-body text-xl font-semibold text-zap-ink md:text-2xl">
                Finishing touches
              </h2>
              <p className="mt-1 font-body text-sm text-zap-ink-muted">
                Optional — add an X handle and profile photo, or skip and do this later in settings.
              </p>
            </div>
            <Input
              variant="editorial"
              label="X handle (optional)"
              placeholder="@yourhandle"
              value={form.xHandle}
              onChange={handleChange("xHandle")}
              error={errors.xHandle}
              disabled={isSubmitting}
            />
            <AvatarImageField
              value={form.imageUrl}
              onChange={(next) => {
                setForm((prev) => ({ ...prev, imageUrl: next }));
                setErrors((prev) => ({ ...prev, imageUrl: undefined }));
              }}
              error={errors.imageUrl}
              disabled={isSubmitting}
              variant="editorial"
              fallbackLabel={
                form.displayName.trim() || form.username.trim() || "You"
              }
            />
            {txStatus !== "idle" && (
              <TransactionStatus
                variant="editorial"
                status={txStatus}
                txHash={txHash}
                errorMessage={txError}
                onRetry={handleRegisterTxRetry}
                retryLabel={registerTxRetryLabel}
              />
            )}
          </div>
        )}

        <div className="flex flex-col gap-3 border-t border-zap-border pt-6 sm:flex-row sm:items-center sm:justify-between">
          <div>
            {step > 0 ? (
              <button
                type="button"
                onClick={goBack}
                disabled={isSubmitting}
                className="inline-flex items-center gap-2 font-body text-sm font-medium text-zap-ink-muted transition-colors hover:text-zap-ink disabled:opacity-50"
              >
                <ArrowLeft className="h-4 w-4" aria-hidden />
                Back
              </button>
            ) : (
              <span />
            )}
          </div>
          <div className="flex flex-col gap-3 sm:flex-row sm:justify-end">
            {step < 4 ? (
              <button
                type="button"
                disabled={
                  isSubmitting ||
                  (step === 1 &&
                    (checking || available === false || !validateUsername(form.username).valid))
                }
                className="btn-primary inline-flex w-full min-h-[48px] min-w-[200px] font-body items-center justify-center px-8 normal-case tracking-normal disabled:pointer-events-none disabled:opacity-50 sm:w-auto"
                onClick={goNext}
              >
                {step === 0 && !connected ? "Connect wallet" : "Continue"}
              </button>
            ) : (
              <button
                type="submit"
                disabled={
                  isSubmitting ||
                  checking ||
                  available === false ||
                  !validateUsername(form.username).valid ||
                  !validateDisplayName(form.displayName).valid
                }
                className="btn-primary inline-flex w-full min-h-[48px] min-w-[220px] font-body items-center justify-center px-8 normal-case tracking-normal disabled:pointer-events-none disabled:opacity-50 sm:w-auto"
              >
                {isSubmitting ? "Creating…" : "Create your page"}
              </button>
            )}
          </div>
        </div>
      </form>
    </div>
  );
};

export default RegisterWizard;
